
let eventData = [
  { name: 'EMP Asteroid', desc: 'EMP Asteroids spawned outside the safezone.' },
  { name: 'Asteroid Shower', desc: 'Asteroids are raining into the safezone, try to mine them before they explode.' },
  { name: 'EMP Burst', desc: 'A EMP zone will begin to grow, don\'t get caught!' },
  { name: 'Colossal Asteroid', desc: 'Colossal Asteroid' },
  { name: 'Caravan', desc: 'A Caravan has appeared near the outer layer, intercept them for loot!' },
  { name: 'Asteroid Just Passing By', desc: 'Don\'t even mind him, mans just chillin' },
  /*{ name: 'Alien Mothership', desc: 'A large ship has been spotted outside the safezone, destroy it for cash.' },*/
  /*{ name: 'Wormhole', desc: 'A wormhole has opened, enter it to teleport to the other side.', once: true },*/
];
let events = window.events = {};

window.randomEvent = function() {
  let event = eventData[Math.floor(Math.random() * eventData.length)];
  if (sim.hasActivePlayers === true) sim.say(`[EVENT] ${event.name}: ${event.desc}`);
  events[event.name]();
};

events['Black Hole'] = function() {
  if (sim.hasActivePlayers === true) sim.say('A black hole has appeared!!');
  let bh = new types.BlackHole();
  bh.pos = [0, 0];
  sim.things[bh.id] = bh;
  sim.blackhole = true;
};

events['Safezone Collapse'] = function(pos) {
  if (sim.hasActivePlayers === true) sim.say('The safezone is collapsing.');
  sim.safezone.collapse = true;
};

