function spawnUnit(spec, pos, color, data = {}) {
  let unit = new types.Unit(spec);
  unit.owner = -1;
  unit.side = 'resource';
  unit.color = color;
  unit.pos = pos;
  unit.rot = Math.random() * Math.PI * 2;
  for (let i in data) unit[i] = data[i];
  sim.things[unit.id] = unit;
  return unit;
}
function ringPos(pos, origin, minRadius, maxRadius) {
  let theta = Math.random() * Math.PI * 2;
  pos[0] = origin[0] + Math.cos(theta) * (minRadius + Math.random() * (maxRadius - minRadius));
  pos[1] = origin[1] + Math.sin(theta) * (minRadius + Math.random() * (maxRadius - minRadius));
  return theta;
}
let genAsteroid = window.genAsteroid = function(data, pos, count) {
  for (let i = 0; i < count; i ++) {
    let asteroid = new types.Asteroid();
    let rand = Math.random();
    if (!data.noRespawn) {
      asteroid.spawnData = data;
      asteroid.spawnPos = pos;
    }
    asteroid.radius = data.radius[0] + rand * data.radius[1];
    asteroid.hp = data.hp[0] + rand * data.hp[1];
    asteroid.cost = Math.round(data.cost[0] + rand * data.cost[1]);
    asteroid.mass = data.mass[0] + rand * data.mass[1];
    asteroid.color = [data.color[0] + Math.random() * 20, data.color[1] + Math.random() * 20, data.color[2] + Math.random() * 20, 255];
    for (let d in data) {
      if (d === 'radius' || d === 'hp' || d === 'cost' || d === 'mass' || d === 'color') continue;
      asteroid[d] = data[d];
    }
    ringPos(asteroid.pos, pos[0], pos[1], pos[2]);
    let n = 0;
    while (true) {
      n ++;
      let overlap = false;
      for (let k in sim.asteroids) {
        if (v2.distance(asteroid.pos, sim.asteroids[k].pos) < asteroid.radius + sim.asteroids[k].radius + 100) {
          overlap = true;
          break;
        }
      }
      for (let k = 0; k < sim.markets.length; k ++) {
        if (v2.distance(asteroid.pos, sim.markets[k].pos) < asteroid.radius + sim.markets[k].radius + 500) {
          overlap = true;
          break;
        }
      }
      if (overlap && n < 10) ringPos(asteroid.pos, pos[0], pos[1], pos[2]);
      else break;
    }
    asteroid.init();
    sim.things[asteroid.id] = asteroid;
    sim.asteroids[asteroid.id] = asteroid;
  }
};

